function maxArea(height) {
  let left = 0;
  let right = height.length - 1;
  let max = 0;
  while (left < right) {
    const area = Math.min(height[left], height[right]) * (right - left);
    if (area > max) max = area;
    if (height[left] <= height[right]) { left++; continue; }
    right--;
  }
  return max;
}
